const DEFAULT_SETTINGS = { difficulty: "intermediate", holdMult: 1.0, repeatWeak: true, weakThresh: 70, breathGuide: true, cameraFacing: "user" };
function loadSettings() { try { return { ...DEFAULT_SETTINGS, ...JSON.parse(localStorage.getItem("sn_settings") || "{}") }; } catch { return { ...DEFAULT_SETTINGS }; } }
function saveSettings(s) { localStorage.setItem("sn_settings", JSON.stringify(s)); }
const DIFF_DELTA = { beginner: 15, intermediate: 0, advanced: -8 };
function applyDiff(thresh, mode) { const d = DIFF_DELTA[mode] || 0; if (!d) return thresh; const out = {}; Object.entries(thresh).forEach(([k, [mn, mx]]) => { out[k] = [Math.max(0, mn - d), Math.min(180, mx + d)]; }); return out; }

