/* ═══ MEDIAPIPE ═══ */
const CONNECTIONS = [[11, 12], [11, 13], [13, 15], [12, 14], [14, 16], [11, 23], [12, 24], [23, 24], [23, 25], [25, 27], [24, 26], [26, 28]];
function angleBetween(a, b, c) { if (!a || !b || !c) return 0; const ba = { x: a.x - b.x, y: a.y - b.y }, bc = { x: c.x - b.x, y: c.y - b.y }; const dot = ba.x * bc.x + ba.y * bc.y; const mag = Math.sqrt(ba.x ** 2 + ba.y ** 2) * Math.sqrt(bc.x ** 2 + bc.y ** 2); return mag === 0 ? 0 : (Math.acos(Math.min(1, Math.max(-1, dot / mag))) * 180) / Math.PI; }
function computeAngles(lm) { if (!lm || lm.length < 29) return {}; const g = i => lm[i]; return { leftElbow: angleBetween(g(11), g(13), g(15)), rightElbow: angleBetween(g(12), g(14), g(16)), leftShoulder: angleBetween(g(13), g(11), g(23)), rightShoulder: angleBetween(g(14), g(12), g(24)), leftHip: angleBetween(g(11), g(23), g(25)), rightHip: angleBetween(g(12), g(24), g(26)), leftKnee: angleBetween(g(23), g(25), g(27)), rightKnee: angleBetween(g(24), g(26), g(28)) }; }
function evaluatePose(angles, pose, difficulty = "intermediate") { const thresh = applyDiff(pose.thresholds, difficulty); const keys = Object.keys(thresh); if (!keys.length) return { correct: false, score: 0, feedback: [] }; let passed = 0; const feedback = []; keys.forEach(k => { const [mn, mx] = thresh[k], val = angles[k]; if (!val) return; if (val >= mn && val <= mx) passed++; else { const dir = val < mn ? "higher" : "lower"; const joint = k.replace(/([A-Z])/g, " $1").trim(); feedback.push(`${joint}: ${Math.round(val)} deg - aim ${mn}-${mx} (go ${dir})`); } }); const valid = keys.filter(k => angles[k] > 0).length; const score = valid > 0 ? Math.round((passed / valid) * 100) : 0; return { correct: score >= 65, score, feedback }; }

/* ═══ COMPONENTS ═══ */
function RadialProgress({ value, size = 80, stroke = 6, color = "#F59E0B", label, glow }) { const r = (size - stroke) / 2, circ = 2 * Math.PI * r, offset = circ - (value / 100) * circ; return (<div style={{ position: "relative", width: size, height: size, display: "flex", alignItems: "center", justifyContent: "center" }}><svg width={size} height={size} style={{ transform: "rotate(-90deg)", position: "absolute" }}><circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke="rgba(255,255,255,0.07)" strokeWidth={stroke} /><circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke={color} strokeWidth={stroke} strokeDasharray={circ} strokeDashoffset={offset} strokeLinecap="round" style={{ transition: "stroke-dashoffset 0.45s ease", filter: glow ? `drop-shadow(0 0 8px ${color})` : "none" }} /></svg><div style={{ textAlign: "center", zIndex: 1 }}><div style={{ fontSize: size < 70 ? 13 : size < 100 ? 18 : 24, fontWeight: 800, color: "#fff", fontFamily: "'JetBrains Mono',monospace" }}>{Math.round(value)}</div>{label && <div style={{ fontSize: 8, color: "rgba(255,255,255,0.38)", letterSpacing: 1.2, textTransform: "uppercase" }}>{label}</div>}</div></div>); }
function HoldRing({ progress, color, seconds }) { const sz = 112, st = 9, r = (sz - st) / 2, circ = 2 * Math.PI * r, offset = circ - (progress / 100) * circ; return (<div style={{ position: "relative", width: sz, height: sz, display: "flex", alignItems: "center", justifyContent: "center" }}><svg width={sz} height={sz} style={{ transform: "rotate(-90deg)", position: "absolute" }}><circle cx={sz / 2} cy={sz / 2} r={r} fill="none" stroke="rgba(34,197,94,0.1)" strokeWidth={st} /><circle cx={sz / 2} cy={sz / 2} r={r} fill="none" stroke={color} strokeWidth={st} strokeDasharray={circ} strokeDashoffset={offset} strokeLinecap="round" style={{ transition: "stroke-dashoffset 0.1s linear", filter: `drop-shadow(0 0 12px ${color})` }} /></svg><div style={{ textAlign: "center", zIndex: 1 }}><div style={{ fontSize: 11, fontWeight: 800, color, fontFamily: "'JetBrains Mono',monospace" }}>HOLD</div><div style={{ fontSize: 26, fontWeight: 800, color: "#fff", fontFamily: "'JetBrains Mono',monospace", lineHeight: 1 }}>{seconds}</div><div style={{ fontSize: 9, color: "rgba(255,255,255,0.38)" }}>seconds</div></div></div>); }
function AngleBar({ name, value, threshold }) { const inRange = threshold ? value >= threshold[0] && value <= threshold[1] : null; const col = inRange === null ? "#6B7280" : inRange ? "#22C55E" : "#EF4444"; return (<div style={{ marginBottom: 7 }}><div style={{ display: "flex", justifyContent: "space-between", marginBottom: 2.5 }}><span style={{ fontSize: 10, color: "rgba(255,255,255,0.4)", textTransform: "capitalize" }}>{name.replace(/([A-Z])/g, " $1").trim()}</span><span style={{ fontSize: 10, color: col, fontFamily: "'JetBrains Mono',monospace" }}>{Math.round(value)} [{threshold ? `${threshold[0]}-${threshold[1]}` : ""}]</span></div><div style={{ height: 3, background: "rgba(255,255,255,0.06)", borderRadius: 2, overflow: "hidden" }}><div style={{ width: `${Math.min(100, (value / 180) * 100)}%`, height: "100%", background: col, borderRadius: 2, transition: "width 0.25s" }} /></div></div>); }

/* RefImage — objectFit contain so full image shows */
function RefImage({ pose }) { const [failed, setFailed] = useState(false); return (<div><div style={{ fontSize: 9, letterSpacing: 1.8, textTransform: "uppercase", color: "rgba(255,255,255,0.25)", padding: "12px 13px 6px" }}>Reference Posture</div><div style={{ margin: "0 10px 10px", borderRadius: 14, overflow: "hidden", border: `1.5px solid ${pose.color}44`, position: "relative", background: "#0c1018", minHeight: 180 }}>{!failed ? (<img src={pose.referenceImage} alt={pose.name} onError={() => setFailed(true)} style={{ width: "100%", height: "100%", objectFit: "contain", display: "block", background: "#f5f5f0" }} />) : (<div style={{ width: "100%", height: 180, display: "flex", alignItems: "center", justifyContent: "center", background: `${pose.color}09` }}><div style={{ fontSize: 16, color: "rgba(255,255,255,0.42)", fontWeight: 600 }}>{pose.name}</div></div>)}<div style={{ position: "absolute", bottom: 0, left: 0, right: 0, background: "linear-gradient(transparent,rgba(5,8,18,0.95))", padding: "22px 12px 10px" }}><div style={{ display: "flex", alignItems: "center", gap: 5, marginBottom: 2 }}><span style={{ fontSize: 9.5, color: pose.color, fontWeight: 700 }}>{pose.breath}</span><span style={{ fontSize: 9.5, color: "rgba(255,255,255,0.28)", marginLeft: 4 }}>| Hold {pose.holdRequired}s</span></div><div style={{ fontSize: 13, fontWeight: 700, color: pose.color }}>{pose.name}</div><div style={{ fontSize: 9.5, color: "rgba(255,255,255,0.35)" }}>{pose.sanskrit}</div></div></div></div>); }
function Toggle({ on, onChange, color = "#F59E0B" }) { return (<div onClick={() => onChange(!on)} style={{ width: 44, height: 24, borderRadius: 12, background: on ? color : "rgba(255,255,255,0.1)", cursor: "pointer", position: "relative", transition: "background 0.3s", flexShrink: 0 }}><div style={{ position: "absolute", top: 3, left: on ? 22 : 3, width: 18, height: 18, borderRadius: 9, background: "#fff", transition: "left 0.25s", boxShadow: "0 1px 4px rgba(0,0,0,0.4)" }} /></div>); }

/* ═══ SETTINGS PANEL ═══ */
function SettingsPanel({ settings, onChange, onCalibrate, onFlipCamera }) { const s = settings; const set = (k, v) => onChange({ ...s, [k]: v }); return (<div style={{ flex: 1, overflow: "auto", padding: "24px 20px" }}><div style={{ maxWidth: 520, margin: "0 auto" }}><div style={{ fontSize: 22, fontWeight: 800, marginBottom: 4, background: "linear-gradient(90deg,#F59E0B,#EF4444)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>Settings</div><div style={{ fontSize: 12, color: "rgba(255,255,255,0.32)", marginBottom: 24 }}>Personalise your practice</div><div style={{ padding: "14px 16px", borderRadius: 12, border: "1px solid rgba(255,255,255,0.07)", background: "rgba(255,255,255,0.025)", marginBottom: 12 }}><div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}><div><div style={{ fontWeight: 700, fontSize: 14 }}>Camera</div><div style={{ fontSize: 11, color: "rgba(255,255,255,0.38)", marginTop: 2 }}>Currently: {s.cameraFacing === "user" ? "Front" : "Back"}</div></div><button onClick={onFlipCamera} style={{ padding: "7px 16px", borderRadius: 9, border: "1.5px solid rgba(245,158,11,0.4)", background: "rgba(245,158,11,0.1)", color: "#F59E0B", fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "'Outfit',sans-serif" }}>Flip Camera</button></div></div><div style={{ height: 1, background: "rgba(255,255,255,0.06)", margin: "20px 0" }} /><div style={{ fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: "rgba(255,255,255,0.3)", marginBottom: 10 }}>Difficulty Mode</div>{[["beginner", "Beginner", "Wider tolerance"], ["intermediate", "Intermediate", "Standard"], ["advanced", "Advanced", "Strict"]].map(([k, lbl, desc]) => (<div key={k} onClick={() => set("difficulty", k)} style={{ padding: "14px 16px", borderRadius: 12, border: `1.5px solid ${s.difficulty === k ? "rgba(245,158,11,0.6)" : "rgba(255,255,255,0.07)"}`, background: s.difficulty === k ? "rgba(245,158,11,0.1)" : "rgba(255,255,255,0.025)", cursor: "pointer", marginBottom: 8 }}><div style={{ fontWeight: 700, fontSize: 14, color: s.difficulty === k ? "#F59E0B" : "rgba(255,255,255,0.75)" }}>{lbl}</div><div style={{ fontSize: 11, color: "rgba(255,255,255,0.38)", marginTop: 2 }}>{desc}</div></div>))}<div style={{ height: 1, background: "rgba(255,255,255,0.06)", margin: "20px 0" }} /><div style={{ marginBottom: 20 }}><div style={{ fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: "rgba(255,255,255,0.3)", marginBottom: 10 }}>Hold Duration: {s.holdMult.toFixed(1)}x</div><input type="range" min={0.5} max={2.0} step={0.1} value={s.holdMult} onChange={e => set("holdMult", parseFloat(e.target.value))} style={{ width: "100%", accentColor: "#F59E0B" }} /></div><div style={{ height: 1, background: "rgba(255,255,255,0.06)", margin: "20px 0" }} /><div style={{ padding: "14px 16px", borderRadius: 12, border: "1px solid rgba(255,255,255,0.07)", background: "rgba(255,255,255,0.025)", marginBottom: 12 }}><div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}><div><div style={{ fontWeight: 700, fontSize: 14 }}>Repeat Weak Poses</div><div style={{ fontSize: 11, color: "rgba(255,255,255,0.38)", marginTop: 2 }}>Retry below {s.weakThresh}%</div></div><Toggle on={s.repeatWeak} onChange={v => set("repeatWeak", v)} /></div></div><div style={{ padding: "14px 16px", borderRadius: 12, border: "1px solid rgba(255,255,255,0.07)", background: "rgba(255,255,255,0.025)", marginBottom: 12 }}><div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}><div><div style={{ fontWeight: 700, fontSize: 14 }}>Breathing Guide</div><div style={{ fontSize: 11, color: "rgba(255,255,255,0.38)", marginTop: 2 }}>Show inhale/exhale cues</div></div><Toggle on={s.breathGuide} onChange={v => set("breathGuide", v)} /></div></div><div style={{ height: 1, background: "rgba(255,255,255,0.06)", margin: "20px 0" }} /><div style={{ padding: "14px 16px", borderRadius: 12, border: "1px solid rgba(255,255,255,0.07)", background: "rgba(255,255,255,0.025)" }}><div style={{ fontWeight: 700, fontSize: 14, marginBottom: 2 }}>Body Calibration</div><div style={{ fontSize: 11, color: "rgba(255,255,255,0.38)", marginBottom: 12 }}>Detect body proportions</div><button onClick={onCalibrate} style={{ padding: "9px 20px", borderRadius: 9, border: "1.5px solid rgba(245,158,11,0.4)", background: "rgba(245,158,11,0.1)", color: "#F59E0B", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "'Outfit',sans-serif" }}>Start Calibration</button></div></div></div>); }

function CalibrationModal({ onClose, latestLmRef }) { const [phase, setPhase] = useState("instructions"); const [countdown, setCountdown] = useState(3); const [result, setResult] = useState(null); const timerRef = useRef(null); function startCapture() { setPhase("detecting"); let ct = 3; setCountdown(ct); timerRef.current = setInterval(() => { ct--; if (ct > 0) setCountdown(ct); else { clearInterval(timerRef.current); captureCalib(); } }, 1000); } function captureCalib() { try { const lm = latestLmRef.current; if (!lm || lm.length < 29) { setPhase("error"); return; } const sw = Math.abs(lm[11].x - lm[12].x); const th = Math.abs(((lm[11].y + lm[12].y) / 2) - ((lm[23].y + lm[24].y) / 2)); const lh = Math.abs(((lm[23].y + lm[24].y) / 2) - ((lm[27].y + lm[28].y) / 2)); const r = th > 0 ? lh / th : 1; const c = { shoulderW: Math.round(sw * 1e3) / 1e3, torsoH: Math.round(th * 1e3) / 1e3, legH: Math.round(lh * 1e3) / 1e3, ratio: Math.round(r * 100) / 100, ts: Date.now() }; localStorage.setItem("sn_calib", JSON.stringify(c)); setResult(c); setPhase("done"); } catch { setPhase("error"); } } useEffect(() => () => clearInterval(timerRef.current), []); return (<div style={{ position: "fixed", inset: 0, background: "rgba(5,8,18,0.93)", backdropFilter: "blur(10px)", zIndex: 100, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}><div style={{ background: "#0f1623", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 20, padding: "28px 26px", maxWidth: 400, width: "100%" }}><div style={{ fontSize: 20, fontWeight: 800, marginBottom: 4 }}>Body Calibration</div>{phase === "instructions" && <><div style={{ fontSize: 13, color: "rgba(255,255,255,0.5)", lineHeight: 1.7, marginBottom: 20 }}>Stand in <strong style={{ color: "#F59E0B" }}>Tadasana</strong> (arms at sides, facing camera). Make sure your full body is visible.</div><div style={{ display: "flex", gap: 10 }}><button onClick={startCapture} style={{ flex: 1, padding: "11px", borderRadius: 11, border: "none", background: "linear-gradient(135deg,#F59E0B,#EF4444)", color: "#fff", fontSize: 14, fontWeight: 700, cursor: "pointer" }}>Begin</button><button onClick={onClose} style={{ padding: "11px 18px", borderRadius: 11, border: "1px solid rgba(255,255,255,0.1)", background: "transparent", color: "rgba(255,255,255,0.5)", fontSize: 13, cursor: "pointer" }}>Cancel</button></div></>}{phase === "detecting" && <div style={{ textAlign: "center", padding: "30px 0" }}><div style={{ fontSize: 64, fontWeight: 800, color: "#F59E0B", fontFamily: "'JetBrains Mono',monospace" }}>{countdown}</div><div style={{ fontSize: 13, color: "rgba(255,255,255,0.45)", marginTop: 8 }}>Hold still...</div></div>}{phase === "done" && result && <><div style={{ background: "rgba(34,197,94,0.08)", border: "1px solid rgba(34,197,94,0.3)", borderRadius: 12, padding: 14, marginBottom: 16 }}><div style={{ fontSize: 13, color: "#22C55E", fontWeight: 700, marginBottom: 8 }}>Calibration Complete</div><div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>{[["Shoulder", result.shoulderW], ["Torso", result.torsoH], ["Leg", result.legH], ["Ratio", result.ratio]].map(([k, v]) => (<div key={k} style={{ background: "rgba(255,255,255,0.03)", borderRadius: 8, padding: "8px 10px" }}><div style={{ fontSize: 9, color: "rgba(255,255,255,0.35)", textTransform: "uppercase" }}>{k}</div><div style={{ fontSize: 15, fontWeight: 700, fontFamily: "'JetBrains Mono',monospace" }}>{v}</div></div>))}</div></div><button onClick={onClose} style={{ width: "100%", padding: "11px", borderRadius: 11, border: "none", background: "linear-gradient(135deg,#F59E0B,#EF4444)", color: "#fff", fontSize: 14, fontWeight: 700, cursor: "pointer" }}>Done</button></>}{phase === "error" && <><div style={{ color: "#EF4444", fontSize: 13, marginBottom: 16 }}>Could not detect body. Make sure camera is enabled and you are visible.</div><div style={{ display: "flex", gap: 10 }}><button onClick={() => setPhase("instructions")} style={{ flex: 1, padding: "11px", borderRadius: 11, border: "none", background: "rgba(245,158,11,0.2)", color: "#F59E0B", fontSize: 13, fontWeight: 700, cursor: "pointer" }}>Retry</button><button onClick={onClose} style={{ padding: "11px 18px", borderRadius: 11, border: "1px solid rgba(255,255,255,0.1)", background: "transparent", color: "rgba(255,255,255,0.5)", fontSize: 13, cursor: "pointer" }}>Cancel</button></div></>}</div></div>); }


/* ═══ POSE PICKER ═══ */
function PosePicker({ currentIdx, completed, onSelect, onClose }) { return (<div style={{ position: "fixed", inset: 0, background: "rgba(5,8,18,0.92)", backdropFilter: "blur(10px)", zIndex: 90, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}><div style={{ background: "#0f1623", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 20, padding: "24px 20px", maxWidth: 520, width: "100%", maxHeight: "80vh", overflow: "auto" }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}><div style={{ fontSize: 18, fontWeight: 800, background: "linear-gradient(90deg,#F59E0B,#EF4444)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>Jump to Pose</div><button onClick={onClose} style={{ width: 30, height: 30, borderRadius: 8, border: "1px solid rgba(255,255,255,0.1)", background: "transparent", color: "#fff", fontSize: 16, cursor: "pointer" }}>X</button></div><div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>{POSES.map((p, i) => { const done = completed.includes(i); const active = i === currentIdx; return (<button key={i} onClick={() => { onSelect(i); onClose(); }} style={{ padding: "12px", borderRadius: 12, border: `1.5px solid ${active ? p.color : done ? "rgba(34,197,94,0.3)" : "rgba(255,255,255,0.07)"}`, background: active ? `${p.color}18` : done ? "rgba(34,197,94,0.06)" : "rgba(255,255,255,0.02)", cursor: "pointer", textAlign: "left", fontFamily: "'Outfit',sans-serif" }}><div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4 }}><span style={{ fontSize: 10, color: "rgba(255,255,255,0.3)", fontFamily: "'JetBrains Mono',monospace" }}>#{i + 1}</span>{done && <span style={{ fontSize: 9, color: "#22C55E", fontWeight: 700 }}>DONE</span>}</div><div style={{ fontSize: 12, fontWeight: 700, color: active ? p.color : "#fff" }}>{p.name}</div><div style={{ fontSize: 9, color: "rgba(255,255,255,0.35)", marginTop: 2 }}>{p.sanskrit}</div></button>); })}</div></div></div>); }

/* ═══ HELPER: save history ═══ */
function saveHistory(h) { localStorage.setItem("sn_history", JSON.stringify(h)); }

/* ═══ MAIN APP ═══ */
export default function SuryaTrackApp() {
  const videoRef = useRef(null); const canvasRef = useRef(null); const detectorRef = useRef(null); const rafRef = useRef(null); const holdRef = useRef(null); const sessActive = useRef(false); const holdActive_ = useRef(false); const poseIdxRef = useRef(0); const streamRef = useRef(null); const lastFeedbackRef = useRef([]); const poseScoresRef = useRef([]); const latestLmRef = useRef(null);
  const [settings, setSettings] = useState(loadSettings); const [isPortrait, setIsPortrait] = useState(window.innerHeight > window.innerWidth); const [mpLoading, setMpLoading] = useState(false); const [camActive, setCamActive] = useState(false); const [camErr, setCamErr] = useState(""); const [sessionState, setSessionState] = useState("idle"); const [poseIdx, setPoseIdx] = useState(0); const [result, setResult] = useState({ correct: false, score: 0, feedback: [] }); const [holdActive, setHoldActive] = useState(false); const [holdProgress, setHoldProgress] = useState(0); const [holdSecs, setHoldSecs] = useState(0); const [angles, setAngles] = useState({}); const [detecting, setDetecting] = useState(false); const [poseScores, setPoseScores] = useState([]); const [completed, setCompleted] = useState([]); const [showRedo, setShowRedo] = useState(false); const [transition, setTransition] = useState(""); const [tab, setTab] = useState("session"); const [guide, setGuide] = useState(0); const [showCalib, setShowCalib] = useState(false); const [showPicker, setShowPicker] = useState(false); const [histDetail, setHistDetail] = useState(null);
  const [history, setHistory] = useState(() => { try { return JSON.parse(localStorage.getItem("sn_history") || "[]"); } catch { return []; } });

  useEffect(() => { const h = () => setIsPortrait(window.innerHeight > window.innerWidth); window.addEventListener("resize", h); window.addEventListener("orientationchange", h); return () => { window.removeEventListener("resize", h); window.removeEventListener("orientationchange", h); }; }, []);
  useEffect(() => { const canvas = canvasRef.current; if (!canvas) return; const ro = new ResizeObserver(entries => { for (const e of entries) { const { width, height } = e.contentRect; if (width > 0 && height > 0) { canvas.width = width * (window.devicePixelRatio || 1); canvas.height = height * (window.devicePixelRatio || 1); } } }); ro.observe(canvas); return () => ro.disconnect(); }, []);
  useEffect(() => { saveSettings(settings); }, [settings]);
  useEffect(() => { poseIdxRef.current = poseIdx; }, [poseIdx]);
  useEffect(() => { holdActive_.current = holdActive; }, [holdActive]);
  useEffect(() => { sessActive.current = sessionState === "active"; }, [sessionState]);
  useEffect(() => { poseScoresRef.current = poseScores; }, [poseScores]);

  const pose = POSES[poseIdx]; const overall = poseScores.length ? Math.round(poseScores.reduce((a, b) => a + b.score, 0) / poseScores.length) : 0; const isCorrect = result.correct; const isFront = settings.cameraFacing === "user";

  const captureScreenshot = useCallback(() => { try { const v = videoRef.current; if (!v || v.videoWidth === 0) return null; const c = document.createElement("canvas"); c.width = v.videoWidth; c.height = v.videoHeight; c.getContext("2d").drawImage(v, 0, 0); return c.toDataURL("image/jpeg", 0.5); } catch { return null; } }, []);

  const drawSkeleton = useCallback((lm, correct) => { const canvas = canvasRef.current; if (!canvas || !lm) return; const ctx = canvas.getContext("2d"); const w = canvas.width, h = canvas.height; ctx.clearRect(0, 0, w, h); ctx.save(); const col = correct ? "#22C55E" : "#FFFFFF"; ctx.lineWidth = 2; ctx.strokeStyle = col; ctx.shadowColor = correct ? "#22C55E" : "rgba(255,255,255,0.3)"; ctx.shadowBlur = correct ? 12 : 4; ctx.globalAlpha = 0.9; CONNECTIONS.forEach(([i, j]) => { const a = lm[i], b = lm[j]; if (!a || !b || a.visibility < 0.3 || b.visibility < 0.3) return; ctx.beginPath(); ctx.moveTo(a.x * w, a.y * h); ctx.lineTo(b.x * w, b.y * h); ctx.stroke(); }); ctx.shadowBlur = correct ? 8 : 3; ctx.globalAlpha = 1;[0, 11, 12, 13, 14, 15, 16, 23, 24, 25, 26, 27, 28].forEach(i => { const pt = lm[i]; if (!pt || pt.visibility < 0.3) return; ctx.beginPath(); ctx.arc(pt.x * w, pt.y * h, 4, 0, Math.PI * 2); ctx.fillStyle = col; ctx.fill(); ctx.beginPath(); ctx.arc(pt.x * w, pt.y * h, 2, 0, Math.PI * 2); ctx.fillStyle = correct ? "#bbf7d0" : "#e0e0e0"; ctx.fill(); }); ctx.restore(); }, []);

  const loadScripts = useCallback(() => new Promise(resolve => { const srcs = ["https://cdn.jsdelivr.net/npm/@mediapipe/camera_utils@0.3/camera_utils.js", "https://cdn.jsdelivr.net/npm/@mediapipe/drawing_utils@0.3/drawing_utils.js", "https://cdn.jsdelivr.net/npm/@mediapipe/pose@0.5/pose.js"]; let done = 0; srcs.forEach(src => { if (document.querySelector(`script[src="${src}"]`)) { done++; if (done === srcs.length) resolve(); return; } const s = document.createElement("script"); s.src = src; s.crossOrigin = "anonymous"; s.onload = s.onerror = () => { done++; if (done === srcs.length) resolve(); }; document.head.appendChild(s); }); }), []);

  const startCamera = useCallback(async (facing) => { setCamErr(""); setMpLoading(true); if (streamRef.current) { streamRef.current.getTracks().forEach(t => t.stop()); streamRef.current = null; } if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; } try { await loadScripts(); if (!window.Pose) throw new Error("MediaPipe failed"); if (!detectorRef.current) { const det = new window.Pose({ locateFile: f => `https://cdn.jsdelivr.net/npm/@mediapipe/pose@0.5/${f}` }); det.setOptions({ modelComplexity: 1, smoothLandmarks: true, enableSegmentation: false, minDetectionConfidence: 0.3, minTrackingConfidence: 0.3 }); det.onResults(res => { const lm = res.poseLandmarks; latestLmRef.current = lm || null; if (lm) { const a = computeAngles(lm); const idx = poseIdxRef.current; const r = evaluatePose(a, POSES[idx], settings.difficulty); setAngles(a); setResult(r); setDetecting(true); lastFeedbackRef.current = r.feedback; drawSkeleton(lm, r.correct); if (sessActive.current) { if (r.correct && !holdActive_.current) beginHold(r.score, idx); else if (!r.correct && holdActive_.current) { abortHold(); setShowRedo(true); } } } else { setDetecting(false); const c = canvasRef.current; if (c) c.getContext("2d").clearRect(0, 0, c.width, c.height); } }); detectorRef.current = det; } const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: facing || "user", width: { ideal: 640 }, height: { ideal: 480 } } }); streamRef.current = stream; videoRef.current.srcObject = stream; await videoRef.current.play(); setCamActive(true); setMpLoading(false); const loop = async () => { if (detectorRef.current && videoRef.current && videoRef.current.readyState >= 2) { try { await detectorRef.current.send({ image: videoRef.current }); } catch (e) { } } rafRef.current = requestAnimationFrame(loop); }; loop(); } catch (e) { setCamErr(e.message || "Camera error"); setMpLoading(false); } }, [loadScripts, drawSkeleton, settings.difficulty]);

  const flipCamera = useCallback(() => { const nf = settings.cameraFacing === "user" ? "environment" : "user"; setSettings(s => ({ ...s, cameraFacing: nf })); if (camActive) startCamera(nf); }, [settings.cameraFacing, camActive, startCamera]);

  function beginHold(score, idx) { holdActive_.current = true; setHoldActive(true); setShowRedo(false); setHoldProgress(0); const req = POSES[idx].holdRequired * settings.holdMult * 1000; let el = 0; clearInterval(holdRef.current); holdRef.current = setInterval(() => { el += 100; const prog = Math.min(100, (el / req) * 100); setHoldProgress(prog); setHoldSecs(Math.max(0, Math.ceil((req - el) / 1000))); if (el >= req) { clearInterval(holdRef.current); holdActive_.current = false; setHoldActive(false); setHoldProgress(0); advancePose(score, idx); } }, 100); }
  function abortHold() { clearInterval(holdRef.current); holdActive_.current = false; setHoldActive(false); setHoldProgress(0); }

  /* ═══ KEY CHANGE: save session to history IMMEDIATELY after each pose ═══ */
  function saveSessionToHistory(scores, isComplete) {
    if (!scores || scores.length === 0) return;
    const avg = Math.round(scores.reduce((a, b) => a + b.score, 0) / scores.length);
    const rec = { date: new Date().toLocaleString(), overallScore: avg, poses: scores.length, complete: isComplete, details: scores.map(p => ({ name: POSES[p.poseIdx].name, poseIdx: p.poseIdx, score: p.score, feedback: p.feedback || [], screenshot: p.screenshot || null })) };
    setHistory(prev => {
      // Replace the latest "in-progress" session or add new one
      let upd;
      if (prev.length > 0 && prev[0].sessionId === rec.date) {
        upd = [rec, ...prev.slice(1)];
      } else if (!isComplete && prev.length > 0 && !prev[0].complete) {
        upd = [rec, ...prev.slice(1)]; // replace ongoing
      } else {
        upd = [rec, ...prev].slice(0, 20);
      }
      saveHistory(upd); return upd;
    });
  }

  function advancePose(score, idx) {
    const screenshot = captureScreenshot(); const fb = lastFeedbackRef.current.slice(0, 3);
    const newScores = [...poseScoresRef.current, { poseIdx: idx, score, feedback: fb, screenshot }];
    setPoseScores(newScores); poseScoresRef.current = newScores;
    setCompleted(p => [...p, idx]); setShowRedo(false);
    // Auto-save after every pose
    saveSessionToHistory(newScores, idx >= POSES.length - 1);
    setTransition(`${POSES[idx].name} - ${Math.round(score)}%`);
    setTimeout(() => { setTransition(""); if (idx >= POSES.length - 1) { setSessionState("complete"); if (settings.repeatWeak) { const weak = newScores.filter(p => p.score < settings.weakThresh).sort((a, b) => a.score - b.score); if (weak.length > 0) { setTimeout(() => { if (window.confirm(`Struggled with ${POSES[weak[0].poseIdx].name} (${Math.round(weak[0].score)}%). Repeat?`)) { jumpToPose(weak[0].poseIdx); } }, 2000); } } } else { const n = idx + 1; setPoseIdx(n); poseIdxRef.current = n; setResult({ correct: false, score: 0, feedback: [] }); } }, 1700);
  }

  function jumpToPose(idx) { abortHold(); setPoseIdx(idx); poseIdxRef.current = idx; setShowRedo(false); setTransition(""); setResult({ correct: false, score: 0, feedback: [] }); if (sessionState !== "active") setSessionState("active"); }

  function startSession() { abortHold(); setPoseIdx(0); poseIdxRef.current = 0; setPoseScores([]); poseScoresRef.current = []; setCompleted([]); setShowRedo(false); setTransition(""); setResult({ correct: false, score: 0, feedback: [] }); setSessionState("active"); }
  function resetSession() {
    abortHold();
    // Save whatever progress was made as partial session
    if (poseScoresRef.current.length > 0) { saveSessionToHistory(poseScoresRef.current, false); }
    sessActive.current = false; setSessionState("idle"); setPoseIdx(0); setPoseScores([]); poseScoresRef.current = []; setCompleted([]); setShowRedo(false); setAngles({}); setResult({ correct: false, score: 0, feedback: [] });
  }

  if (isPortrait) return (<div style={{ height: "100vh", width: "100vw", background: "#07090F", color: "white", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 30, textAlign: "center", fontFamily: "'Outfit',sans-serif" }}><div style={{ fontSize: 36, fontWeight: 800, marginBottom: 12, color: "#F59E0B" }}>Rotate Device</div><p style={{ color: "rgba(255,255,255,0.5)", lineHeight: 1.6, maxWidth: 280 }}>SuryaTrack works in landscape mode.</p></div>);

  return (<>
    <style>{`@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800&family=JetBrains+Mono:wght@400;500;700&display=swap');*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}body{background:#07090F;overflow:hidden;}::-webkit-scrollbar{width:3px;}::-webkit-scrollbar-thumb{background:rgba(255,255,255,0.1);border-radius:2px;}@keyframes slideU{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}@keyframes blinkA{0%,100%{opacity:1}50%{opacity:0.3}}.su{animation:slideU .35s ease forwards;}.bl{animation:blinkA .8s infinite;}button{font-family:'Outfit',sans-serif;cursor:pointer;}.hv{transition:opacity .15s,transform .15s;}.hv:hover{opacity:.8;transform:scale(1.03);}`}</style>
    {showCalib && <CalibrationModal onClose={() => setShowCalib(false)} latestLmRef={latestLmRef} />}
    {showPicker && <PosePicker currentIdx={poseIdx} completed={completed} onSelect={jumpToPose} onClose={() => setShowPicker(false)} />}
    <div style={{ height: "100vh", width: "100vw", background: "#07090F", color: "#fff", fontFamily: "'Outfit',sans-serif", display: "flex", flexDirection: "column", overflow: "hidden" }}>
      <header style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 16px", borderBottom: "1px solid rgba(255,255,255,0.05)", background: "rgba(7,9,15,0.98)", flexShrink: 0, zIndex: 20 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}><div style={{ width: 32, height: 32, borderRadius: 8, background: "linear-gradient(135deg,#F59E0B,#EF4444)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 800, color: "#fff" }}>ST</div><div style={{ fontSize: 14, fontWeight: 800, background: "linear-gradient(90deg,#F59E0B,#EF4444)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>SuryaTrack AI</div></div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          {camActive && <button className="hv" onClick={flipCamera} style={{ padding: "5px 10px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.1)", background: "rgba(255,255,255,0.04)", color: "#F59E0B", fontSize: 11, fontWeight: 600 }}>{isFront ? "Front" : "Back"} Cam</button>}
          <nav style={{ display: "flex", gap: 3, background: "rgba(255,255,255,0.04)", borderRadius: 10, padding: 3 }}>{[["session", "Session"], ["history", "Log"], ["guide", "Guide"], ["settings", "Settings"]].map(([t, l]) => (<button key={t} onClick={() => { setTab(t); setHistDetail(null); }} style={{ padding: "5px 12px", borderRadius: 8, border: "none", fontSize: 11, fontWeight: 500, background: tab === t ? "rgba(245,158,11,0.18)" : "transparent", color: tab === t ? "#F59E0B" : "rgba(255,255,255,0.38)" }}>{l}</button>))}</nav>
        </div>
      </header>
      {sessionState === "active" && <div style={{ height: 6, background: "rgba(255,255,255,0.05)", display: "flex", cursor: "pointer" }} onClick={() => setShowPicker(true)}>{POSES.map((p, i) => (<div key={i} style={{ flex: 1, borderRight: "1px solid rgba(0,0,0,0.3)", background: completed.includes(i) ? "#22C55E" : i === poseIdx ? p.color : "transparent", transition: "background 0.3s" }} />))}</div>}
      <div style={{ flex: 1, overflow: "hidden", display: "flex" }}>
        <main style={{ flex: 2, display: "flex", flexDirection: "column", overflow: "hidden", minWidth: 0, position: "relative" }}>
          <div style={{ flex: 1, position: "relative", background: "#060810", overflow: "hidden" }}>
            <video ref={videoRef} playsInline muted autoPlay style={{ width: "100%", height: "100%", objectFit: "cover", opacity: camActive ? 1 : 0, transform: isFront ? "scaleX(-1)" : "none", display: "block" }} />
            <canvas ref={canvasRef} style={{ position: "absolute", top: 0, left: 0, width: "100%", height: "100%", pointerEvents: "none", transform: isFront ? "scaleX(-1)" : "none" }} />
            {!camActive && <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 14 }}><div style={{ fontSize: 18, fontWeight: 700, color: "rgba(255,255,255,0.15)" }}>Camera Preview</div><button className="hv" onClick={() => startCamera(settings.cameraFacing)} style={{ padding: "12px 28px", borderRadius: 12, border: "none", fontSize: 13, fontWeight: 700, background: "linear-gradient(135deg,#F59E0B,#EF4444)", color: "#fff" }}>{mpLoading ? "Loading AI..." : "Enable Camera"}</button>{camErr && <div style={{ color: "#EF4444", fontSize: 11 }}>{camErr}</div>}</div>}
            {sessionState === "active" && <>
              <div style={{ position: "absolute", top: 12, right: 12, background: "rgba(5,8,18,0.72)", backdropFilter: "blur(10px)", borderRadius: 10, padding: "6px 8px", border: `1px solid ${isCorrect ? "rgba(34,197,94,0.3)" : "rgba(255,255,255,0.07)"}`, transform: "scale(0.85)", transformOrigin: "top right" }}><RadialProgress value={result.score} size={60} color={isCorrect ? "#22C55E" : "#F59E0B"} label="Score" glow={isCorrect} /></div>
              <button onClick={() => setShowPicker(true)} style={{ position: "absolute", top: 12, left: 12, padding: "6px 14px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.15)", background: "rgba(5,8,18,0.72)", color: "#F59E0B", fontSize: 11, fontWeight: 700 }}>Pose {poseIdx + 1}/12</button>
              {settings.breathGuide && !holdActive && !transition && <div className="su bl" style={{ position: "absolute", top: "15%", left: "50%", transform: "translateX(-50%)", fontSize: 28, fontWeight: 800, color: "rgba(255,255,255,0.7)", textShadow: "0 2px 10px rgba(0,0,0,0.8)" }}>{pose.breath}</div>}
              {isCorrect && !holdActive && !transition && <div className="su" style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", background: "rgba(34,197,94,0.14)", border: "1.5px solid rgba(34,197,94,0.5)", borderRadius: 50, padding: "10px 24px" }}><span style={{ fontSize: 13, fontWeight: 700, color: "#22C55E" }}>Correct - Hold Still</span></div>}
              {holdActive && !transition && <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)" }}><HoldRing progress={holdProgress} color="#22C55E" seconds={holdSecs} /></div>}
              {transition && <div className="su" style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", background: "rgba(34,197,94,0.14)", border: "1.5px solid rgba(34,197,94,0.5)", borderRadius: 14, padding: "16px 30px", textAlign: "center" }}><div style={{ fontSize: 15, fontWeight: 700, color: "#22C55E" }}>{transition}</div></div>}
              {showRedo && !holdActive && !transition && <div className="su" style={{ position: "absolute", bottom: 60, left: "50%", transform: "translateX(-50%)" }}><button className="hv" onClick={() => { abortHold(); setShowRedo(false); setResult({ correct: false, score: 0, feedback: [] }); }} style={{ padding: "10px 26px", borderRadius: 50, border: "1.5px solid rgba(245,158,11,0.5)", fontSize: 13, fontWeight: 700, background: "rgba(245,158,11,0.14)", color: "#F59E0B" }}>Redo Pose</button></div>}
              {!detecting && <div style={{ position: "absolute", bottom: 60, right: 12, background: "rgba(239,68,68,0.12)", border: "1px solid rgba(239,68,68,0.25)", borderRadius: 8, padding: "6px 10px" }}><div style={{ fontSize: 10, color: "#EF4444" }}>No body detected</div></div>}
            </>}
            {sessionState === "complete" && <div style={{ position: "absolute", inset: 0, background: "rgba(5,8,18,0.95)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 12, zIndex: 10 }}><div style={{ fontSize: 20, fontWeight: 800, background: "linear-gradient(90deg,#F59E0B,#EF4444)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>Cycle Complete</div><RadialProgress value={overall} size={100} stroke={8} color="#F59E0B" label="Overall" glow /><div style={{ display: "flex", gap: 10, marginTop: 4 }}><button className="hv" onClick={startSession} style={{ padding: "8px 22px", borderRadius: 9, border: "none", fontSize: 12, fontWeight: 700, background: "linear-gradient(135deg,#F59E0B,#EF4444)", color: "#fff" }}>Repeat</button><button className="hv" onClick={resetSession} style={{ padding: "8px 18px", borderRadius: 9, border: "1px solid rgba(255,255,255,0.1)", fontSize: 12, background: "rgba(255,255,255,0.05)", color: "#fff" }}>Done</button></div></div>}
          </div>
          <div style={{ padding: "8px 12px", borderTop: "1px solid rgba(255,255,255,0.05)", background: "rgba(5,8,18,0.97)", display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
            {sessionState === "idle" && camActive && <button className="hv" onClick={startSession} style={{ flex: 1, padding: "10px 0", borderRadius: 10, border: "none", fontSize: 13, fontWeight: 700, background: "linear-gradient(135deg,#F59E0B,#EF4444)", color: "#fff" }}>Begin Session</button>}
            {sessionState === "active" && <><div style={{ flex: 1, display: "flex", alignItems: "center", gap: 8 }}><div style={{ fontSize: 13, fontWeight: 700, color: pose.color }}>{pose.name}</div><button onClick={() => setShowPicker(true)} style={{ fontSize: 10, color: "rgba(255,255,255,0.5)", background: "rgba(255,255,255,0.06)", border: "none", borderRadius: 6, padding: "3px 8px" }}>Pose {poseIdx + 1}/12</button></div><button className="hv" onClick={resetSession} style={{ padding: "6px 14px", borderRadius: 8, border: "1px solid rgba(239,68,68,0.28)", fontSize: 11, fontWeight: 600, background: "rgba(239,68,68,0.08)", color: "#EF4444" }}>Stop</button></>}
          </div>
        </main>
        <aside style={{ flex: 1, borderLeft: "1px solid rgba(255,255,255,0.05)", overflow: "hidden auto", display: "flex", flexDirection: "column", flexShrink: 0, background: "rgba(7,9,15,0.6)", maxWidth: 320 }}>
          {tab === "settings" && <SettingsPanel settings={settings} onChange={setSettings} onCalibrate={() => setShowCalib(true)} onFlipCamera={flipCamera} />}
          {(tab === "session" || tab === "guide") && <><div style={{ flexShrink: 0 }}><RefImage pose={tab === "session" ? pose : POSES[guide]} /></div><div style={{ padding: "0 10px 14px", flex: 1 }}>
            {tab === "session" && sessionState === "active" && <div style={{ marginBottom: 10, padding: "10px 12px", borderRadius: 10, background: isCorrect ? "rgba(34,197,94,0.07)" : "rgba(255,255,255,0.022)", border: `1px solid ${isCorrect ? "rgba(34,197,94,0.32)" : "rgba(255,255,255,0.06)"}` }}><div style={{ fontSize: 11, fontWeight: 700, color: isCorrect ? "#22C55E" : "rgba(255,255,255,0.45)", marginBottom: 6 }}>{isCorrect ? "Correct Form" : "Adjust Posture"}</div>{!isCorrect && result.feedback.slice(0, 2).map((f, i) => (<div key={i} style={{ fontSize: 9.5, color: "rgba(255,255,255,0.6)", padding: "2px 0" }}>{f}</div>))}</div>}
            {tab === "session" && sessionState === "active" && Object.keys(angles).length > 0 && <div style={{ marginBottom: 10 }}><div style={{ fontSize: 8.5, letterSpacing: 1.5, textTransform: "uppercase", color: "rgba(255,255,255,0.3)", marginBottom: 6 }}>Joint Angles</div>{Object.entries(angles).filter(([, v]) => v > 0).map(([k, v]) => (<AngleBar key={k} name={k} value={v} threshold={pose.thresholds[k]} />))}</div>}
            <div style={{ marginBottom: 10 }}><div style={{ fontSize: 8.5, letterSpacing: 1.5, textTransform: "uppercase", color: "rgba(255,255,255,0.3)", marginBottom: 6 }}>Key Points</div>{(tab === "session" ? pose : POSES[guide]).keyPoints.map((kp, i) => (<div key={i} style={{ display: "flex", gap: 6, alignItems: "flex-start", marginBottom: 4 }}><div style={{ width: 4, height: 4, borderRadius: "50%", background: (tab === "session" ? pose : POSES[guide]).color, marginTop: 4.5, flexShrink: 0 }} /><div style={{ fontSize: 10, color: "rgba(255,255,255,0.6)", lineHeight: 1.4 }}>{kp}</div></div>))}</div>
            {tab === "guide" && <div style={{ display: "flex", gap: 6, marginTop: 10 }}><button disabled={guide <= 0} onClick={() => setGuide(g => g - 1)} style={{ flex: 1, padding: "8px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.1)", background: "rgba(255,255,255,0.04)", color: "#fff", fontSize: 11, opacity: guide <= 0 ? .3 : 1 }}>Prev</button><button disabled={guide >= POSES.length - 1} onClick={() => setGuide(g => g + 1)} style={{ flex: 1, padding: "8px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.1)", background: "rgba(255,255,255,0.04)", color: "#fff", fontSize: 11, opacity: guide >= POSES.length - 1 ? .3 : 1 }}>Next</button></div>}
          </div></>}
          {tab === "history" && <div style={{ padding: 16 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}><div style={{ fontSize: 16, fontWeight: 800 }}>Session Log</div>{history.length > 0 && <button onClick={() => { if (window.confirm("Clear all session logs?")) { setHistory([]); saveHistory([]); setHistDetail(null); } }} style={{ padding: "4px 10px", borderRadius: 6, border: "1px solid rgba(239,68,68,0.3)", background: "rgba(239,68,68,0.08)", color: "#EF4444", fontSize: 10, fontWeight: 600, cursor: "pointer" }}>Clear All</button>}</div>
            {histDetail !== null && history[histDetail] ? (<div>
              <button onClick={() => setHistDetail(null)} style={{ marginBottom: 12, padding: "6px 14px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.1)", background: "rgba(255,255,255,0.04)", color: "#F59E0B", fontSize: 11, fontWeight: 600 }}>Back</button>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 }}><div style={{ fontSize: 13, fontWeight: 700 }}>{history[histDetail].date}</div><div style={{ fontSize: 11, padding: "3px 8px", borderRadius: 6, background: history[histDetail].complete ? "rgba(34,197,94,0.1)" : "rgba(245,158,11,0.1)", color: history[histDetail].complete ? "#22C55E" : "#F59E0B", fontWeight: 600 }}>{history[histDetail].complete ? "Complete" : "Partial"}</div></div>
              <div style={{ fontSize: 11, color: "rgba(255,255,255,0.5)", marginBottom: 12 }}>Overall: {history[histDetail].overallScore}% | {history[histDetail].poses} poses</div>
              {(history[histDetail].details || []).map((d, i) => (<div key={i} style={{ padding: 10, borderRadius: 10, background: "rgba(255,255,255,0.03)", marginBottom: 8, border: "1px solid rgba(255,255,255,0.06)" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}><div style={{ fontSize: 12, fontWeight: 700 }}>{d.name}</div><div style={{ fontSize: 13, fontWeight: 800, color: d.score >= 70 ? "#22C55E" : "#F59E0B", fontFamily: "'JetBrains Mono',monospace" }}>{d.score}%</div></div>
                {d.screenshot && <img src={d.screenshot} alt={d.name} style={{ width: "100%", borderRadius: 8, marginBottom: 6, border: "1px solid rgba(255,255,255,0.08)" }} />}
                {d.feedback && d.feedback.length > 0 && <div><div style={{ fontSize: 8.5, color: "rgba(255,255,255,0.3)", textTransform: "uppercase", letterSpacing: 1, marginBottom: 4 }}>Improvement Tips</div>{d.feedback.map((f, j) => (<div key={j} style={{ fontSize: 9.5, color: "rgba(255,255,255,0.55)", padding: "2px 0" }}>{f}</div>))}</div>}
                {(!d.feedback || d.feedback.length === 0) && d.score >= 70 && <div style={{ fontSize: 9.5, color: "#22C55E" }}>Great form!</div>}
              </div>))}
            </div>) : (<>
              {history.length === 0 ? <div style={{ fontSize: 11, color: "gray" }}>No sessions yet. Complete at least one pose to see results.</div> : history.map((s, i) => (<div key={i} style={{ padding: 12, borderRadius: 10, background: "rgba(255,255,255,0.03)", marginBottom: 8, border: "1px solid rgba(255,255,255,0.06)", position: "relative" }}>
                <button onClick={(e) => { e.stopPropagation(); const upd = history.filter((_, j) => j !== i); setHistory(upd); saveHistory(upd); }} style={{ position: "absolute", top: 6, right: 6, width: 20, height: 20, borderRadius: 4, border: "1px solid rgba(239,68,68,0.25)", background: "rgba(239,68,68,0.08)", color: "#EF4444", fontSize: 10, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", padding: 0 }}>X</button>
                <div onClick={() => { if (s.details) setHistDetail(i); }} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", cursor: s.details ? "pointer" : "default" }}>
                  <div><div style={{ fontSize: 10, color: "gray" }}>{s.date}</div><div style={{ fontSize: 11, fontWeight: 600 }}>{s.poses} poses {s.complete ? "(Complete)" : "(Partial)"}</div>{s.details && <div style={{ fontSize: 9, color: "#F59E0B", marginTop: 2 }}>Tap for details + screenshots</div>}</div>
                  <div style={{ fontSize: 16, fontWeight: 800, color: s.overallScore >= 70 ? "#22C55E" : "#F59E0B", marginRight: 20 }}>{s.overallScore}%</div>
                </div>
              </div>))}
            </>)}
          </div>}
        </aside>
      </div>
    </div>
  </>);
}
